an class=&#34;token operator&#34;&gt;!&lt;/span&gt;_instance&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token function&#34;&gt;InitializeFromDefault&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;UnityEditor&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;AssetDatabase&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token generic-method&#34;&gt;&lt;span class=&#34;token function&#34;&gt;LoadAssetAtPath&lt;/span&gt;&lt;span class=&#34;token generic class-name&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;GameFileAsset&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Assets/Test game file.asset&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token preprocessor property&#34;&gt;#&lt;span class=&#34;token directive keyword&#34;&gt;endif&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; _instance&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;List&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;Archive&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; archives&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Archive&lt;/span&gt; currArchive&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;InitializeFromDefault&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;GameFileAsset&lt;/span&gt; file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;_instance&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;DestroyImmediate&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;_instance&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            _instance &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Instantiate&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            _instance&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;hideFlags &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; HideFlags&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;HideAndDontSave&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;LoadFromJson&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;string&lt;/span&gt;&lt;/span&gt; path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;!&lt;/span&gt;_instance&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;DestroyImmediate&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;_instance&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           _instance &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; ScriptableObject&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token generic-method&#34;&gt;&lt;span class=&#34;token function&#34;&gt;CreateInstance&lt;/span&gt;&lt;span class=&#34;token generic class-name&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;GameFileAsset&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           JsonUtility&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;FromJsonOverwrite&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;System&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;IO&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;File&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;ReadAllText&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; _instance&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           _instance&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;hideFlags &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; HideFlags&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;HideAndDontSave&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;SaveToJson&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;string&lt;/span&gt;&lt;/span&gt; path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           Debug&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;LogFormat&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Saving game file to &amp;#123;0&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; path&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;           System&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;IO&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;File&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;WriteAllText&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;path&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; JsonUtility&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;ToJson&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;this&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;57&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;61&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;个人理解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#个人理解&#34;&gt;#&lt;/a&gt; 个人理解&lt;/h3&gt;
&lt;p&gt;ScriptableObject 其实就是对类的特殊处理，在 unity 中将这里的类脚本特异性的识别让其数据可视化，并在内部实现了实例化处理，让其可以直接在脚本中使用而无需实例化对象。&lt;/p&gt;
&lt;p&gt;[toc]&lt;/p&gt;

 &lt;p&gt;在上一个文章&lt;a href=&#34;https://www.fasty97.top/lwrp%e4%b8%8bshadergraph%e7%9a%84%e4%bd%bf%e7%94%a8/&#34; title=&#34;LWRP&#34;&gt; LWRP&lt;/a&gt; 中我们介绍了 LWRP 的基本使用方法，并使用 ShaderGraph 写了两个小例子。&lt;br&gt;
这次我们就来尝试一下 HDRP，效果上要比 LWRP 或者普通渲染管线好多少。&lt;/p&gt;
&lt;h3 id=&#34;效果预览&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#效果预览&#34;&gt;#&lt;/a&gt; 效果预览&lt;/h3&gt;
&lt;p&gt;&lt;video src=&#34;https://pic.fasty97.top/blog/blog-nierHDRP.mp4&#34; autoplay loop style=&#34;width:100%&#34;&gt;&lt;/video&gt;&lt;br&gt;
可以看到在 HDRP 中的效果还是比较不错的，各种光影的质量都还不错。&lt;/p&gt;
&lt;h3 id=&#34;hdrp-入门&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#hdrp-入门&#34;&gt;#&lt;/a&gt; HDRP 入门&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;下载安装以下依赖:&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200322/kl15u7a5e2GF.png&#34; alt=&#34;&#34;&gt;&lt;/li&gt;
&lt;li&gt;创建 HDRP 资源并设置（这个和 LWRP 差不多）&lt;/li&gt;
&lt;li&gt;设置颜色空间为 &lt;code&gt;Linner&lt;/code&gt;  (这个设置很重要)&lt;/li&gt;
&lt;li&gt;创建全局 Volm 管理环境&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;以上就是主要的步骤，下面我详细说一下一些细节的地方。&lt;/p&gt;
&lt;h3 id=&#34;如何使用天空盒&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#如何使用天空盒&#34;&gt;#&lt;/a&gt; 如何使用天空盒&lt;/h3&gt;
&lt;p&gt;在 HDRP 中有多种天空类型： &lt;code&gt;颜色渐变天空&lt;/code&gt; ， &lt;code&gt;纯色天空&lt;/code&gt; ， &lt;code&gt;HDRI天空&lt;/code&gt; ， &lt;code&gt;物理天空&lt;/code&gt; 等。&lt;br&gt;
大家可以看到我的天空是有一些云朵的一个天空盒，在 HDRP 中默认是纯色的黑天空，我们可以添加一个 Volume 对象或者在游戏物体上挂载一个 Volume 脚本来对默认设置进行重写。&lt;br&gt;
如我这样我可视化环境组件，用于设置天空类型，这里我将其设置为 HDRI，再添加一个 HDRI Sky 组件用于详细设置，在 Hdri Sky 项目中设置导入的天空盒 cubemap。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200322/WnOvO7pHMlnr.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
添加一个：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200323/i4UgANuYjKXk.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
在设置中设置：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200323/5MV2zF3dOEoE.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
此时就算是把天空盒光线环境搭好了，快放入模型试试吧。&lt;/p&gt;
&lt;h3 id=&#34;金属感和平滑度&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#金属感和平滑度&#34;&gt;#&lt;/a&gt; 金属感和平滑度&lt;/h3&gt;
&lt;p&gt;在这个模型中，2B 所持的剑是金属制品，但之前的之前的视频展示并没有去做这方面的处理。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200323/PjUJNsJzTJ6j.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
这里我将金属度设置为 1，给一个很强的金属感，平滑度给个 0.6。（如我们现实世界一样，一般来说金属度高的东西，平滑度也会高一些，反射光线的能力强一些。）&lt;br&gt;
设置金属和平滑度一部分可以补足金属器物的质感和光泽。&lt;br&gt;
调整金属和平滑度后：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200323/wHbsjytdodBJ.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
视频预览：&lt;br&gt;
&lt;video src=&#34;https://pic.fasty97.top/blog/nierHDRP2.mp4&#34; autoplay loop style=&#34;width:100%&#34;&gt;&lt;/video&gt;&lt;/p&gt;
&lt;p&gt;[toc]&lt;/p&gt;

 &lt;p&gt;&lt;strong&gt;丢失了好多文章，故更新一波，开一个新坑 CG&lt;/strong&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;不论是 LWRP 还是 ShaderGraph 都已经不是什么新技术了&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;cg杂谈&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#cg杂谈&#34;&gt;#&lt;/a&gt; CG 杂谈&lt;/h3&gt;
&lt;p&gt;计算机图形学（ComputGraph）简称 &lt;code&gt;CG&lt;/code&gt; ，是一门研究计算机图形图像处理的学科，将符号或电子信号可视化是一门比较晦涩难懂的东西，比如 &lt;code&gt;傅里叶变换&lt;/code&gt; 用于研究声音和波的关系，让波得以表示。众所周知，建模时我们总是使用三角面来构成一个模型，以三角面的数量来衡量一个模型的精细程度。从三维物体坐标系到二维的屏幕坐标系，深度如何表示？遮挡关系如何计算？这就是 CG 所研究的东西，计算机图形学也被称为程序员的浪漫，这就是这个系列要说的东西。&lt;/p&gt;
&lt;h3 id=&#34;lwrp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#lwrp&#34;&gt;#&lt;/a&gt; LWRP&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;LWRP&lt;/code&gt;  (轻度渲染管线) 是 unity 推出的可自定义的渲染管线，其初衷是为了移动平台和轻度主机平台。在轻度渲染管线下，我们可以对渲染管线做更多的设置和处理，并且可以使用 shaderGraph 可视化的 shader 编辑器像连连看一样完成 shader 的编写。&lt;br&gt;
通过 shader 我们可以实现许多视觉效果，如飘动的红旗，水面的倒影，卡通人物渲染等；有些可以使用模型来解决但使用 shader 不仅高效还能处理许多模型无法解决的东西。&lt;/p&gt;
&lt;p&gt;&lt;em&gt;不知道你是否看过游戏的模型，或者说取解包过游戏，很多游戏，模型可能并没有游戏中那么&lt;strong&gt;漂亮&lt;/strong&gt;！&lt;/em&gt;&lt;br&gt;
但是通过 shader，光照，后处理等，玩家看到的就是非常赞的效果了！（就好像是美颜滤镜一样）&lt;/p&gt;
&lt;h3 id=&#34;hdrp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#hdrp&#34;&gt;#&lt;/a&gt; HDRP&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;HDRP&lt;/code&gt;  (高清渲染管线) 如名字所言，是专门在对画面质量要求较高的主机或 PC 端开发游戏所使用的。（但 unity 开发大型游戏真的够呛，目前在我看来 ue4 可能更适合）&lt;br&gt;
使用 HDRP 我们可以更高程度的自定义我们的渲染系统，要知道在游戏引擎中，渲染占据了很大的一块。&lt;/p&gt;
&lt;h3 id=&#34;shader的基础认知&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#shader的基础认知&#34;&gt;#&lt;/a&gt; Shader 的基础认知？&lt;/h3&gt;
&lt;p&gt;关于 shader 的基础认知，我在之前曾写过一篇文章（虽然没写完），我会抽空把那篇文章写完的。&lt;br&gt;
如果有兴趣不妨去看看：&lt;a href=&#34;http://www.fasty97.top/unity%e5%9b%be%e5%bd%a2%e5%ad%a6-%e6%b8%b2%e6%9f%93%e6%b5%81%e7%a8%8b/&#34; title=&#34;[传送门]unity图形学 渲染流程&#34;&gt;[传送门] unity 图形学 渲染流程&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;lwrp下shadergraph的搭建&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#lwrp下shadergraph的搭建&#34;&gt;#&lt;/a&gt; LWRP 下 Shadergraph 的搭建&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;Unity版本 2019.3.0f6&lt;/code&gt; &lt;br&gt;
 听了这么多，也许你还是比较懵吧，没事。让我们来揭开 shader 的神秘面纱吧&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;首先安装如下依赖包：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/IHRSz6lfegXD.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/BLWb4IR9U5wt.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;创建渲染管线资源并设置：&lt;br&gt;
值得一提的是，在 unity2019.3 中已经将 LWRP 更名为 UWRP 了，unity 想在之后让 LWRP 变成通用的渲染管线取代原先的 Stand 渲染管线；所以我们需要创建一个 UWRP 的资源。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/TR1o545kQ1Nz.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用 UWRP&lt;br&gt;
 首先我们创建一个 Cube，一个材质，一个 PBRGraph（基于物理的 shader）。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;pbrgraph&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pbrgraph&#34;&gt;#&lt;/a&gt; PBRGraph?&lt;/h4&gt;
&lt;p&gt;这里补充一点小知识，所谓 PBR 就是基于物理的渲染，什么叫做基于物理的渲染呢？简单的说就是原先的模型在绘制贴图时，贴图师就会直接在贴图上绘制好高光，粗糙度，磨损等，这是基于经验的固定化的处理。而基于物理的渲染则是通过复杂的计算和光照模型的影响，动态的计算出模型的细节，让模型处于不同的环境中能够有不同的表现，是基于环境影响的。&lt;/p&gt;
&lt;p&gt;打开 PBRGraph：&lt;br&gt;
创建如下结点并连接&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/KC6HrUGWV9pC.png&#34; alt=&#34;PBRGraph&#34;&gt;&lt;br&gt;
 然后将 shader 指定到对应材质，将材质指定到我们的 Cube，尝试调整数值吧。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/PkIawTx0mOAc.gif&#34; alt=&#34;&#34;&gt;&lt;br&gt;
到这里我们已经知道如何基本的使用 shaderGraph 了呢，但你可能会说，这不是自带 shader 就拥有的功能吗？&lt;/p&gt;
&lt;h3 id=&#34;做一个边缘发光效果&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#做一个边缘发光效果&#34;&gt;#&lt;/a&gt; 做一个边缘发光效果&lt;/h3&gt;
&lt;p&gt;下面我们使用菲涅尔效应做一个简单的边缘自发光，其 shadergraph 如图所示，通过菲涅尔结点指定一个发光颜色和强度来实现。（非常简单吧）&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/pmNHEXl7Y02o.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
&lt;strong&gt;效果图：&lt;/strong&gt;&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/dQdztRRmd7pH.gif&#34; alt=&#34;边缘发光效果&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;做一个顶点动画&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#做一个顶点动画&#34;&gt;#&lt;/a&gt; 做一个顶点动画&lt;/h3&gt;
&lt;p&gt;通过顶点偏移我们可以实现一个波浪或是，旗帜飘动的效果：&lt;br&gt;
主要是使用顶点偏移通过 sin 正弦方式。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/oKWCf4A3lDxM.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;效果如图：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200321/5yqXJieqbu2x.gif&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;blockquote&gt;
&lt;p&gt;最近挺迷漫画的，但如何正确优雅的看漫画却是一大难题&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;pc端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#pc端&#34;&gt;#&lt;/a&gt; PC 端&lt;/h3&gt;
&lt;p&gt;在 Pc 端看漫画还是蛮爽的，屏幕比较大，看的字迹也会清楚一些。&lt;/p&gt;
&lt;h4 id=&#34;漫画阅读器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#漫画阅读器&#34;&gt;#&lt;/a&gt; 漫画阅读器&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Cover&lt;br&gt;
cover 可以直接在 win10 商店下载，免费版可以同时管理 25 本漫画书，并且可以搭载云服务器同步您的漫画库，操作起来非常顺手，缺点是打开页数较多的漫画时，可能加载会较慢。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200316/6s1teEz5I3JI.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Eriri&lt;br&gt;
Eriri 是 &lt;code&gt;蝉时雨&lt;/code&gt; 大佬的开源项目，能够无限制的管理漫画书，操作简洁，加载漫画迅速，但在一些小方面仍需改进，如缺少漫画分类库，缺少日漫的从右至左的阅读方式等。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200316/YSuhMUmh2t5Q.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2NoYW5zaGl5dWN4L2VyaXJp&#34;&gt;github&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;移动端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#移动端&#34;&gt;#&lt;/a&gt; 移动端&lt;/h3&gt;
&lt;p&gt;在移动端可以方便的随时随地看漫画，当然移动端的软件可不必 PC 端差哦。&lt;/p&gt;
&lt;h4 id=&#34;tachiyomi&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#tachiyomi&#34;&gt;#&lt;/a&gt; tachiyomi&lt;/h4&gt;
&lt;p&gt;我强烈安利 tachiyomi,tachiyomi 完全开源免费，由全世界的动漫爱好者一同维护和迭代，现在的版本已经非常稳定和方便了，可以通过添加插件的方式，方便的查看和下载国内外的漫画，并且可绑定云存储容器实现漫画库的实时同步，使用原生 android 开发，流畅度极佳！&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200320/9hulbq79NiLw.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2lub3JpY2hpL3RhY2hpeW9taQ==&#34;&gt;github&lt;/span&gt;&lt;/p&gt;
&lt;h4 id=&#34;exview&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#exview&#34;&gt;#&lt;/a&gt; Exview&lt;/h4&gt;
&lt;p&gt;Exview 不仅仅是一个漫画阅读器，更像是一个二次元圈子，通过各种各样的插件和扩展，不仅能使用 Exview 来看漫画，更可以看小说，看动漫，看 coser 等等；但整体软件非 android 原生开发，且优化极差，导致经常卡死，此软件也有电脑版，但依然存在这些问题。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200320/cWFnI8KVrldf.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;下载漫画&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#下载漫画&#34;&gt;#&lt;/a&gt; 下载漫画&lt;/h3&gt;
&lt;p&gt;下载漫画我推荐使用 漫画控，买个授权也挺便宜的。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200316/NCm32ijzDtjY.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;blockquote&gt;
  有没有想过整理一下自己杂乱的学习笔记呢？有没有想自己写本书呢？
&lt;/blockquote&gt;
&lt;p&gt;如果你有以上的想法，那么 gitbook 将是非常适合你的东西。&lt;/p&gt;
&lt;h3&gt;前置准备工作&lt;/h3&gt;
&lt;p&gt;安装并配置好&lt;code&gt;node.js&lt;/code&gt;即可。&lt;/p&gt;
&lt;h3&gt;安装gitbook&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash line-numbers&#34;&gt;$ npm install gitbook-cli -g
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;安装可能会比较耗时，若情况特殊请开启科学上网。&lt;br&gt;
在安装完成后可以查看是否安装成功：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash line-numbers&#34;&gt;$ gitbook -V
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;使用gitbook&lt;/h3&gt;
&lt;p&gt;在你想建立 gitbook 的文件下，输入&lt;code&gt;gitbook init&lt;/code&gt;可以在此文件夹建立 gitbook。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/note/20200216/0lPmKdMw8l0v.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
你可以在文件中中发现这两个文件：（第一次可能有点慢）&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/note/20200216/CPTnLXSDjhBW.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
其中&lt;code&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL1NVTU1BUlkubWQ=&#34;&gt;SUMMARY.md&lt;/span&gt;&lt;/code&gt;是本书的目录，我们可以编辑目录后再次使用&lt;code&gt;gitbook init&lt;/code&gt;来更新书本。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-markdown line-numbers&#34;&gt;# Summary

* [Introduction](README.md)

* [笔记](note1/笔记.md)

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;我们可以在 SUMMARY 下追加一个目录如上，其中&lt;a class=&#34;wp-editor-md-post-content-link&#34; href=&#34;指向的文件地址&#34;&gt;在目录中显示的名字&lt;/a&gt;，gitbook 会自动生成目录和文件。&lt;br&gt;
然后我们更新书本。&lt;/p&gt;
&lt;h3&gt;启动本地预览&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash line-numbers&#34;&gt;gitbook serve
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200216/ya5J8QhAWmmk.png&#34; alt=&#34;本地预览&#34;&gt;&lt;br&gt;
完成后我们就可以在 4000 端口访问了。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200216/p1IYlSMUaJDd.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;使用vscode编辑MD&lt;/h3&gt;
&lt;p&gt;主要需要安装 2 个插件：&lt;br&gt;
!{}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3BpYy5mYXN0eTk3LnRvcC9ibG9nLzIwMjAwMjE2LzUxa0lRZHBhMVgzZC5wbmc=&#34;&gt;http://pic.fasty97.top/blog/20200216/51kIQdpa1X3d.png&lt;/span&gt;)&lt;br&gt;
!{}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3BpYy5mYXN0eTk3LnRvcC9ibG9nLzIwMjAwMjE2L0lqR3N2TzM3R1MxVy5wbmc=&#34;&gt;http://pic.fasty97.top/blog/20200216/IjGsvO37GS1W.png&lt;/span&gt;)&lt;/p&gt;
&lt;p&gt;安装完这两个插件就可以愉快的写 md 了，可以使用&lt;code&gt;alt+shirt+f&lt;/code&gt;快速格式化代码。&lt;br&gt;
在这里还推荐大家一个插件用于记录文件的更新时间:&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200216/Kq43IQrCOP4P.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
 效果如图：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200216/jBHBzThH1Rof.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Unity 版本号：&lt;font color=green&gt;2019.3.0f6&lt;/font&gt;&lt;/p&gt;
&lt;hr /&gt;
&lt;p&gt;TimeLine 是 unity2017 推出的新功能，其采用时间线的形式组合场景资源， 可以用于编排游戏剧情，过场动画，斩杀镜头，人物特写等效果。&lt;/p&gt;
&lt;h3&gt;创建TimeLine&lt;/h3&gt;
&lt;p&gt;用于播放 TimeLine 的物体必须有这个组件：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/CUXzMDxo2tsx.png&#34; alt=&#34;组件&#34;&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
  &lt;th align=&#34;center&#34;&gt;参数名&lt;/th&gt;
  &lt;th align=&#34;center&#34;&gt;作用&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
  &lt;td align=&#34;center&#34;&gt;Playable&lt;/td&gt;
  &lt;td align=&#34;center&#34;&gt;Playable资源（TimeLine资源）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td align=&#34;center&#34;&gt;Update Method&lt;/td&gt;
  &lt;td align=&#34;center&#34;&gt;更新模式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td align=&#34;center&#34;&gt;Play On Awake&lt;/td&gt;
  &lt;td align=&#34;center&#34;&gt;是否启动时自动播放&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td align=&#34;center&#34;&gt;Wrap Mode&lt;/td&gt;
  &lt;td align=&#34;center&#34;&gt;结束模式，None播放完回到原先属性，Loop循环播放，Hood播放完维持改变&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td align=&#34;center&#34;&gt;Initial Time&lt;/td&gt;
  &lt;td align=&#34;center&#34;&gt;延迟时间&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3&gt;轨道面板&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/0l1DQytDcsA2.png&#34; alt=&#34;轨道面板&#34;&gt;&lt;br&gt;
点击左侧的＋，可以添加轨道，这是一个类似视频剪辑的界面，我们可以方便的对轨道进行移动和剪辑。&lt;/p&gt;
&lt;h4&gt;Activation&lt;/h4&gt;
&lt;p&gt;Activation 用于表示物体的激活状态：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/vIzC588mJlSO.gif&#34; alt=&#34;Activation&#34;&gt;&lt;/p&gt;
&lt;h4&gt;Animation&lt;/h4&gt;
&lt;p&gt;Animation 用于播放动画，既可以播放已有的动画，也可以自己录制帧动画来使用。&lt;br&gt;
&lt;strong&gt;注意：使用此轨道的物体会被创建一个 Animator Controller，这个组件不能被删除。&lt;/strong&gt;&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/gizvroAPPTAo.gif&#34; alt=&#34;Animation&#34;&gt;&lt;/p&gt;
&lt;h4&gt;Audio&lt;/h4&gt;
&lt;p&gt;Audio 轨道用于播放音效，如果不指定 AudioSource 就无法细致调节效果。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/zEYKWKgDJrlk.png&#34; alt=&#34;Audio&#34;&gt;&lt;br&gt;
 每个轨道在属性面板都有不同的属性，Audio 面板如下：&lt;br&gt;
!{Audio 属性}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3BpYy5mYXN0eTk3LnRvcC9ibG9nLzIwMjAwMjEwL0dvRURiN3FiZFNIUi5wbmc=&#34;&gt;http://pic.fasty97.top/blog/20200210/GoEDb7qbdSHR.png&lt;/span&gt;)&lt;/p&gt;
&lt;h4&gt;Control&lt;/h4&gt;
&lt;p&gt;Control 轨道和 Activation 轨道有点相似，但不同的是 Control 轨道可以同时控制多个物体的激活状态。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/y5G5Rhig2kPn.png&#34; alt=&#34;Control&#34;&gt;&lt;/p&gt;
&lt;h4&gt;Signal-任意轨道&lt;/h4&gt;
&lt;p&gt;Signal 是非常重要的轨道，在使用 TimeLine 时，你可能会有这样的想法，能不能在时间线上，调用我们自定义的方法呢，在 2019 之前可以通过剪辑间接的完成事件的调用；但现在有了 Signal 轨道的加持，我们可以非常方便的在任意时刻调用方法了。&lt;br&gt;
创建一个简单的测试脚本，并将脚本挂载在游戏物体上。&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;SignalTest&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token type-list&#34;&gt;&lt;span class=&#34;token class-name&#34;&gt;MonoBehaviour&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Show&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      Debug&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Signal!&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;右键单击任意轨道：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/SAiR90ho2iVi.gif&#34; alt=&#34;&#34;&gt;&lt;br&gt;
此时在属性面板中，可以看到：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/rkIgMqVhBiI3.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
为了监听这个事件，unity 提示我们缺少一个监听器，点击 Add 添加一个。&lt;br&gt;
添加好监听器，我们需要创建一个监听实例，这个实例是可以复用的。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/fbn8zd2A3rD3.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;完成以上步骤我们发现原先有警告的小白标变成了&lt;font color=red&gt;白色&lt;/font&gt;。这说明我们设置正确了，然后我们需要绑定事件给实例：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/YYCEgJkFVtkl.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
尝试运行（播放游戏）一下发现在时间轴运行到小白标时会自动调用我们绑定的方法。&lt;/p&gt;
&lt;h3&gt;Signal-指定轨道&lt;/h3&gt;
&lt;p&gt;上面实现的 Signal 是针对于任意轨道来说的，如果我们需要很多的 Signal 处理起来可能会发生混乱，所以官方提供了专门的 Signal 轨道。&lt;br&gt;
先给我们的物体添加：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/07nzVWaY41Yw.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
在属性面板中我们可以对事件实例绑定多个方法，统一管理：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/IvGBUJotShrO.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;小技巧&lt;/h3&gt;
&lt;p&gt;在轨道左侧可以点击三点，然后选择 Mute（静音）对指定轨道进行屏蔽。&lt;br&gt;
在右侧轨道面板中，可以通过重叠区块实现 2 个区块之间的过渡效果。&lt;br&gt;
可设置轨道的淡入淡出效果：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/TKt9DScaWgab.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;驱动摄像机&lt;/h3&gt;
&lt;p&gt;做了一个超级丑的摄像机变换效果：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/blog/20200210/UVEeBVXqcg7D.gif&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;代码驱动TimeLine&lt;/h3&gt;
&lt;p&gt;有时候我们可能需要通过代码动态的启动 TimeLine，这也很容易实现：&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Signal&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token type-list&#34;&gt;&lt;span class=&#34;token class-name&#34;&gt;MonoBehaviour&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;PlayableDirector&lt;/span&gt; playDir&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Fac&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        Debug&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Fac..&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Update&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Input&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;GetKeyDown&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;KeyCode&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;A&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;A&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            playDir&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Play&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;blockquote&gt;
  之前一直使用的SM.MS的图床个人感觉也蛮好的，直到前几天突然被墙了（虽然现在又好了），但以此作为教训，还是弄个稳定的图床好了。
&lt;/blockquote&gt;
&lt;h3&gt;快速开始&lt;/h3&gt;
&lt;p&gt;首先你需要一个已经&lt;font color=blue&gt;备案&lt;/font&gt;的域名。其次你需要创建一个七牛云账号并绑定一个&lt;font color=blue&gt;加速域名&lt;/font&gt;。&lt;/p&gt;
&lt;h4&gt;创建加速域名&lt;/h4&gt;
&lt;p&gt;创建好一个空间，点击绑定加速域名，输入一个二级地址。&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/2020-02-10-11-57-04.png&#34; alt=&#34;创建加速域名&#34;&gt;&lt;/p&gt;
&lt;h4&gt;在域名服务商处开启CAME&lt;/h4&gt;
&lt;p&gt;创建完成后，复制对应的 CAME 值：&lt;br&gt;
如我创建的加速域名为&lt;code&gt;cdn.fasty97.top&lt;/code&gt;&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/2020-02-10-12-00-10.png&#34; alt=&#34;CAME&#34;&gt;&lt;/p&gt;
&lt;p&gt;在域名解析里添加一条记录：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/2020-02-10-12-04-56.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
然后你可以在七牛云里面看到：&lt;br&gt;
&lt;img data-src=&#34;http://pic.fasty97.top/2020-02-10-12-07-38.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;处理&lt;/h3&gt;
&lt;p&gt;为了方便大家上传图片，我这里使用 2 种不同的方案，大家&lt;font color=red&gt;选择其一&lt;/font&gt;即可。&lt;/p&gt;
&lt;h4&gt;下载MPic&lt;/h4&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL21waWMubHpoYW9mdS5jbi8=&#34;&gt;MPic&lt;/span&gt;&lt;/p&gt;
&lt;h4&gt;下载MarkdownPicPicker&lt;/h4&gt;
&lt;p&gt;MarkdownPicPicker 是一个 md 写作工具，用于上传图片。&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2tpbmduYW1lL01hcmtkb3duUGljUGlja2VyL3JlbGVhc2VzL2Rvd25sb2FkL3YxLjAuMC9NYXJrZG93blBpY1BpY2tlcl92MS4wLjAuemlw&#34;&gt;下载程式&lt;/span&gt;&lt;br&gt;
下载后创建一个 config 文件夹，并将 config.ini 配置好再放进去。&lt;/p&gt;
&lt;p&gt;config.ini 示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;[basic]
picture_folder = pic #必需，用来在本地保存图片的副本，名字任意
picture_suffix = png #必需，图片后缀名，请使用png
# 图片上传插件的文件名，不带&#34;.py&#34;
picture_host = QiniuUploader

[QiniuUploader]
access_key = Q6sS422O0fasfsassadasdfahqasdftqvyQasdf5Zvzw
secret_key = 6QtA121TxoSxZadffsdfasdfaaffasCmoOaB2aLObM
container_name = picturebed
url = http://7sbpmp.com1.z0.glb.clouddn.com/&amp;#123;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：在实际使用中，请将上面的注释部分去掉，避免出现不必要的问题。&lt;/p&gt;
&lt;p&gt;如果你希望只将图片的 url 复制到剪贴板中，而不是复制&lt;code&gt;&lt;img data-src=&#34;%E5%9B%BE%E7%89%87url&#34; alt=&#34;&#34;&gt;&lt;/code&gt;， 你可以为 markdownpicpicker.exe 添加上 -linkonly 参数。在 markdownpicpicker.exe 所在目录打开 cmd, 输入:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;markdownpicpicker.exe -linkonly
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;建议大家使用 AutoHotKey 来启动程序。这样可以把整个流程缩短到 2 秒钟。AutoHotKey 的配置示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;#n::Run D:\Program Files\MarkdownPicPicker_v1.0.0\MarkdownPicPicker_v1.0.0\MarkdownPicPicker.exe -linkonly
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;需要首先使用 QQ 截图或者其他截图工具将图片保存到剪贴板中，然后按下设定好的快捷键即可。Markdown 格式的图片链接就已经保存到剪贴板中了。在需要使用的地方直接粘贴。&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2Foa2NuLnNvdXJjZWZvcmdlLm5ldC9kb2NzL1R1dG9yaWFsLmh0bQ==&#34;&gt;AutoHotKey 的中文文档&lt;/span&gt;&lt;/p&gt;

 &lt;blockquote&gt;
  lua虽然没有面向对象的概念，但我们实现面向对象并不困难
&lt;/blockquote&gt;
&lt;p&gt;一下内容我参考了多处 lua 教程，很多教程讲解模糊晦涩，我整理了以下以简明的说明方式完成 lua 面向对象这部分的内容，希望大家喜欢。&lt;/p&gt;
&lt;h3&gt;面向对象OOP&lt;/h3&gt;
&lt;p&gt;学习过 Java，C#，Ruby 等的同学可能不会对面向对象陌生，如果你是第一次接触面向对象？&lt;br&gt;
那么我总结一下就是:&lt;code&gt;将事物抽象成类，将特征抽象为字段和属性。&lt;/code&gt;&lt;br&gt;
在 Lua 中，最强大的就是 table 这种数据结构了，来看下面这个例子：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;Cat=&amp;#123;name=&#34;defalut&#34;,color=&#34;白色&#34;&amp;#125;
function Cat.say()
    print(Cat.name..&#39;  &#39;..Cat.color..&#39;:&#39;,&#39;喵喵喵~&#39;)
end
Cat.name=&#39;小白&#39;
Cat.say()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;运行结果为:&lt;code&gt;小白  白色：喵喵喵～&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;在例子中，我们创建了一张表，并在表中提供 2 个字段和一个函数，并通过表名。字段名调用字段和方法，这像不像 一个&lt;code&gt;静态类&lt;/code&gt;呢？&lt;br&gt;
以下是 Csharp 的一个类似的静态类：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-csharp line-numbers&#34;&gt;class Program
&amp;#123;
    static void Main(string[] args)
    &amp;#123;
        Cat.name = &#34;小白&#34;;
        Cat.color = &#34;白色&#34;;
        Cat.Show();
    &amp;#125;
&amp;#125;

static class Cat
&amp;#123;
    public static string name;
    public static string color;

    public static void Show()
    &amp;#123;
        System.Console.WriteLine(&#34;&amp;#123;0&amp;#125;  &amp;#123;1&amp;#125;   喵喵喵~&#34;, name, color);
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;分析一下：之所以是静态类是因为我们只在创建表的时候创建了一个对象，后面无论我们进行操作我们都没有创建一个新对象！&lt;/p&gt;
&lt;h3&gt;创建对象&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function Cat:new()
    local o=&amp;#123;&amp;#125;
    setmetatable(o,self)
    self.__index=self
    return o
end

function Cat:say()
    print(self.name..&#39;  &#39;..self.color..&#39;:&#39;,&#39;喵喵喵~&#39;)
end

local ca=Cat:new()
ca:say()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在上面的例子中，我们首先添加了一个 Cat：new 的函数，这类似于我们 Csharp 中的构造函数，&lt;br&gt;
在构造函数中，我们主要做以下几件事：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;创建空表对象&lt;/li&gt;
&lt;li&gt;设置空表的元表&lt;/li&gt;
&lt;li&gt;设置_index&lt;/li&gt;
&lt;li&gt;返回空表对象&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在每次创建对象时，我们都通过:new 函数来创建。&lt;br&gt;
在这里我们使用到了：&lt;code&gt;setmetatable(o,self)&lt;/code&gt;这句话的意思是设置 o 的元表为自己（也就是 Cat 对象），&lt;code&gt;self.__index=self&lt;/code&gt;是设置元方法索引为 Cat 对象，这 2 句话总体就是让对象 o 具有 Cat 对象的属性和函数。&lt;br&gt;
当然元表，元方法的作用还有很多，也远比这要复杂，感兴趣可以自己去了解～&lt;/p&gt;
&lt;h3&gt;继承和多态&lt;/h3&gt;
&lt;p&gt;让我们来看这个例子：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;-- 基础类
Human=&amp;#123;name=&#39;defaultName&#39;,age=0&amp;#125;
function Human:new()
    local o=&amp;#123;&amp;#125;
    self.__index=self
    setmetatable(o,self)
    return o
end

function Human:show()
    print(&#39;Base:&#39;,&#39;Name:&#39;,self.name,&#39;Age:&#39;,self.age)
end

local myhum=Human:new()
myhum.name=&#34;小蓝&#34;
myhum.age=20
myhum:show()

-- 派生类
Chinese=Human:new()
function Chinese:new()
    local o=&amp;#123;&amp;#125;
    setmetatable(o,self)
    self.__index=self
    return o
end
function Chinese:show()
    print(&#39;Chinese:&#39;,&#39;Name:&#39;,self.name,&#39;Age:&#39;,self.age)
end

local ch=Chinese:new()
ch.name=&#34;小红&#34;
ch.age=15
ch:show()

myhum:show()

ch:show()

local ch2=Chinese:new()

ch2:show()


English=Human:new()

function English:show()
    print(&#39;English:&#39;,&#39;Name:&#39;,self.name,&#39;Age:&#39;,self.age)
end

local eg=English:new()
eg.name=&#34;Fasty&#34;;eg.age=22
eg:show()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;!{运行结果}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pLmxvbGkubmV0LzIwMjAvMDIvMDcvMk5FUE9TQ0RYdHVaWUx5LnBuZw==&#34;&gt;https://i.loli.net/2020/02/07/2NEPOSCDXtuZYLy.png&lt;/span&gt;)&lt;/p&gt;
&lt;p&gt;在 lua 中基于弱类型的优势，对于函数重写，只需要重新定义一遍函数即可。&lt;/p&gt;
&lt;p&gt;至此面向对象的封装，继承，多态都实现咯～&lt;/p&gt;
&lt;p&gt;[toc]&lt;/p&gt;

 &lt;p&gt;平时我们在其他语言中，经常会用到如数组，矩阵，队列和栈等一些数据结构，而 lua 似乎并没有这些数据类型，lua 只提供了 table 类型，但是通过 table 类型我们几乎可以实现所有常用的数据类型。&lt;/p&gt;
&lt;h3&gt;数组&lt;/h3&gt;
&lt;p&gt;数组的实现非常简单，table 的数据类型类似与 C# 中的字典，存储 kv 对，我们只取 value 即可。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-lua line-numbers&#34;&gt;local arr=&amp;#123;1,2,3,6,4&amp;#125;

for key, value in pairs(arr) do
    print(key,value)
end
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;矩阵&lt;/h3&gt;
&lt;p&gt;矩阵也被称为多维数组，我们只需要嵌套一个 table 即可。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-lua line-numbers&#34;&gt;local mt=&amp;#123;&amp;#125;
for i = 1, 10 do
    mt[i]=&amp;#123;&amp;#125;
    for j = 1, 10 do
        mt[i][j]=0
    end
end
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;链表&lt;/h3&gt;
&lt;p&gt;对于像链表这样的数据结构，我们可以方便的通过一个指针域实现。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-lua line-numbers&#34;&gt;-- 链表
local l=nil
local l2=&amp;#123;next=nil,value=10&amp;#125;
l=&amp;#123;next=l2,value=200&amp;#125;

while l do
    print(l.value)
    l=l.next
end
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;队列和栈&lt;/h3&gt;
&lt;p&gt;下面以队列为例，栈也是类似的构造：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-lua line-numbers&#34;&gt;-- 队列和栈
Queue=&amp;#123;&amp;#125;
function Queue.new()
    return&amp;#123;first=0,last=-1&amp;#125;
end

function Queue.push(queue,value)
    local first=queue.first-1
    queue.first=first
    queue[first]=value
end

function Queue.pop(queue)
    local last=queue.last
    if queue.last&gt;last then
        error(&#34;queue 为空&#34;)
    end
    local value=queue[last]
    queue[last]=nil
    queue.last=last-1
    return value
end

local qq=Queue.new()
Queue.push(qq,5)
Queue.push(qq,8)
&lt;/code&gt;&lt;/pre&gt;

 &lt;blockquote&gt;
  使用协同程序可以更加高效的处理数据或执行任务
&lt;/blockquote&gt;
&lt;h3&gt;协同的基础&lt;/h3&gt;
&lt;h4&gt;创建协同程序&lt;/h4&gt;
&lt;img data-src=&#34;https://i.loli.net/2020/02/05/QFZCUHvoqLlxs8W.png&#34; alt=&#34;image.png&#34; /&gt;
&lt;pre&gt;&lt;code class=&#34;language-lua line-numbers&#34;&gt;local co=coroutine.create(function ()
    print(&#39;Hi&#39;)
end)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;协程的状态&lt;/h4&gt;
&lt;img data-src=&#34;https://i.loli.net/2020/02/05/jgQadC17IR5UKzs.png&#34; alt=&#34;image.png&#34; /&gt;
协同有三个状态：&lt;code&gt;挂起态&lt;/code&gt;、&lt;code&gt;运行态&lt;/code&gt;、&lt;code&gt;停止态&lt;/code&gt;。当我们创建一个协同程序时他开始的状态为挂起态，也就是说我们创建协同程序的时候不会自动运行，可以使用 status 函数检查协同的状态：
&lt;pre&gt;&lt;code class=&#34;language-lua line-numbers&#34;&gt;print(coroutine.status(co))
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;启动协程&lt;/h4&gt;
&lt;p&gt;使用&lt;code&gt;coroutine.resume()&lt;/code&gt;可以启动协程&lt;br&gt;
&lt;img data-src=&#34;https://i.loli.net/2020/02/05/hfGsy8jZpeYXJK7.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br&gt;
例如：&lt;br&gt;
&lt;code&gt;coroutine.resume(co)&lt;/code&gt;&lt;br&gt;
启动协程后，会立即执行协程方法中的内容。&lt;/p&gt;
&lt;h4&gt;挂起协程&lt;/h4&gt;
&lt;p&gt;如有需要&lt;code&gt;coroutine.yield()&lt;/code&gt;可以挂起协程。&lt;br&gt;
让我们来看下面这个例子，创建一个协程，在协程函数中构建一个循环，并在打印后挂起当前协程，我们不断的去调用协程。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local th=coroutine.create(function ()
    for i = 1, 3 do
        print(&#34;th=&#34;,i)
        coroutine.yield()
    end
end)
coroutine.resume(th)

coroutine.resume(th)
coroutine.resume(th)
coroutine.resume(th)
print(coroutine.resume(th)) -- 程序结束返回false
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其运行结果如下图所示:&lt;br&gt;
&lt;img data-src=&#34;https://i.loli.net/2020/02/05/nbsoW7vOMuGApD4.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br&gt;
我们发现，&lt;strong&gt;在协程死亡时，coroutine.resume 就返回 false，并返回错误消息&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Ps&lt;/strong&gt;:resume 运行在保护模式下，因此如果协同内部存在错误 Lua 并不会抛出错误而是将错误返回给 resume 函数.&lt;/p&gt;
&lt;h4&gt;在resume和yield间交换数据&lt;/h4&gt;
&lt;p&gt;有没有办法在协程挂起时，返回一些数据呢？或在每次启动协程时，发送一些数据？&lt;br&gt;
在 lua 中我们可以在 resume 和 yield 间交换数据。&lt;/p&gt;
&lt;p&gt;传递参数：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;-- 传递参数
local th2=coroutine.create(function (a,b,c)
    print(&#34;th2&#34;,a,b,c)
end)

coroutine.resume(th2,1,2,3)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;当然我们也可以传递协程结果：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local th3=coroutine.create(function ()
    return 6,7
end)

print(coroutine.resume(th3))
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Ps&lt;/strong&gt;:&lt;br&gt;
Lua 提供的这种协同我们称为不对称的协同，就是说挂起一个正在执行的协同的函数与使一个被挂起的协同再次执行的函数是不同的，有些语言提供对称的协同，这种情况下，由执行到挂起之间状态转换的函数是相同的。&lt;/p&gt;
&lt;h3&gt;管道和过滤器&lt;/h3&gt;
&lt;p&gt;这个课题有点难，啃书中。。。&lt;br&gt;
待更新&lt;/p&gt;

 &lt;blockquote&gt;
  lua的特点之一就是方便的调用chunk（代码块）
&lt;/blockquote&gt;
&lt;p&gt;通过这种特性，我们可以在 a.lua 中调用 b.lua 的内容，甚至可以从字符串文本中调用 lua 当做函数执行～&lt;/p&gt;
&lt;h3&gt;load&lt;/h3&gt;
&lt;p&gt;让我们先来看一下 load 函数的定义：&lt;br&gt;
!{load 函数}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pLmxvbGkubmV0LzIwMjAvMDIvMDQvRFlHVjJDU1dvUGNMNDl2LnBuZw==&#34;&gt;https://i.loli.net/2020/02/04/DYGV2CSWoPcL49v.png&lt;/span&gt;)&lt;br&gt;
 通过定义我们可以知道 load 函数可以加载文本和二进制类型代码块，来让我们尝试一下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local f=load(&#39;I=I+1&#39;)
I=0
f()
print(&#39;I=&#39;..I)
f()
print(&#39;I2=&#39;..I)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在这个例子中，我们使用 load 加载了&lt;code&gt;’I=I+1’&lt;/code&gt;这一串字符串，并把加载结果存储在 f 中。通过使用&lt;code&gt;f()&lt;/code&gt;来调用函数。&lt;/p&gt;
&lt;h3&gt;loadFile&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2020/02/04/vNUObGS7D4EczrV.png&#34; alt=&#34;loadFile&#34;&gt;&lt;br&gt;
 和 load 类似的还有 loadfile，但 loadfile 加载的是文件而非字符串。&lt;/p&gt;
&lt;p&gt;我们在 funTest.lua 文件中写一句输出：&lt;code&gt;print(‘Test’)&lt;/code&gt;&lt;br&gt;
然后在其他文件中调用：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local fun=loadfile(&#39;funTest.lua&#39;,&#34;t&#34;)
fun()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;通过这种形式我们就可以吧 funTest.lua 的内容当做一个函数来使用，以上使用后会输出 Test。&lt;/p&gt;
&lt;h3&gt;dofile&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2020/02/04/PxjaiqrlKJ6S41e.png&#34; alt=&#34;dofile&#34;&gt;&lt;br&gt;
dofile 与 loadfile 最大的不同就是，loadfile 只是加载函数，需要我们手动去调用，而 dofile 不但加载函数而且直接调用。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;dofile(&#39;funTest.lua&#39;)
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;require&lt;/h3&gt;
&lt;p&gt;require 是包含的意思，与 load 系列不同的是，require 会检查被加载的文件是否已经被加载过，防止重复加载。&lt;br&gt;
另外使用 require 加载可以单独调用加载的文件中的函数，而不是把文件内容当做一个函数来使用，所以 require 加载时比较理想的加载形式。&lt;/p&gt;
&lt;h4&gt;使用表加载&lt;/h4&gt;
&lt;p&gt;在 funTest.lua 文件中:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local _M = &amp;#123;&amp;#125;
function _M.test()
    print(&#39;hi&#39;)
end
function _M.Hi()
    print(&#39;hi100&#39;)
end
function _M.Say(arg)
    print(&#39;hi:&#39;..tostring(arg))
end
return _M

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在其他文件中调用：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;-- 调用其他文件的函数
local test = require(&#39;funTest&#39;)
if not test then
    print(&#39;错误&#39;)
    return
end
test.Hi()
test.test()
test.Say(51)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;非表加载&lt;/h4&gt;
&lt;p&gt;在 funTest.lua 中：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function Ac(j)
    print(&#39;100:&#39;..j)
end
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在其他文件中：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;require(&#34;funTest&#34;)
Ac(&#39;你好&#39;)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;说明&lt;/h4&gt;
&lt;p&gt;使用表加载和非表加载都可以实现效果，使用表加载时，有点面向对象的感觉可能更方便。&lt;/p&gt;

 &lt;p&gt;在前面我们学习函数时，我们说过函数其实是值，我们可以将函数放在表中。&lt;br&gt;
那么我们是不是可以这么做：&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; fasty&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;a&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; fasty&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;Say:&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; fasty&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Say:&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;在这里，我们创建了一个表 fasty, 表中默认有 a 一个元素。然后我们给表创建了两个函数 say 和 say2，这 2 个函数的作用都是将给与的参数输出。&lt;/p&gt;
&lt;h3&gt;调用不同&lt;/h3&gt;
&lt;p&gt;在我们调用这 2 个方法时，我们应该明确：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;使用&lt;code&gt;.&lt;/code&gt;声明的方法使用&lt;code&gt;.&lt;/code&gt;调用，使用&lt;code&gt;:&lt;/code&gt;声明的方法使用&lt;code&gt;：&lt;/code&gt;调用&lt;/li&gt;
&lt;li&gt;假如我们要使用。调用：声明的方法，那我们需要传递一个 this 指针给函数&lt;/li&gt;
&lt;li&gt;也就是说：其实是自动传递一个 this 指针给函数。&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;fasty&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;100&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;fasty&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;200&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;fasty&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;fasty&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;200&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;```lua&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;strong&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;Ps&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;strong&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;：也就是说一下函数是等效的：&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;```lua&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; fasty&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;say:&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; fasty&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;say:&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3&gt;self指针&lt;/h3&gt;
&lt;p&gt;既然，：的形式是自动传递一个 self 指针给函数，那么就意味着我们可以方便的访问表的元素咯～&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; fasty&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;arg&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Say:&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arg&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;\ta=&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;fasty&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Say2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;200&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2020/02/04/7pvlgWErTAbiSDZ.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;总结&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;使用：声明函数时，函数会将第一个参数默认传递self指针。&lt;/li&gt;
&lt;li&gt;如果使用.调用：声明的函数时，需要第一个参数传递self。：调用则不需要&lt;/li&gt;
&lt;/ul&gt;

 &lt;blockquote&gt;
  迭代器是一种支持指针类型的结构，它可以遍历集合的每一个元素。在 Lua 中我们
  常常使用函数来描述迭代器，每次调用该函数就返回集合的下一个元素。常常使用函数来描述迭代器，每次调用该函数就返回集合的&lt;font color=green&gt;下一个元素&lt;/font&gt;。
&lt;/blockquote&gt;
&lt;h3&gt;闭包和迭代器&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;迭代器需要保留&lt;font color=blue&gt;上一次&lt;/font&gt;成功调用的状态&lt;/li&gt;
&lt;li&gt;迭代器需要保留&lt;font color=blue&gt;下一次&lt;/font&gt;成功调用的状态&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;我们知道闭包可以保留每次调用的状态。并且可以方便的访问局部变量；所以我们也可以使用闭包来构建迭代器。&lt;br&gt;
还记得我们在做 for 循环遍历表时的 pairs (t) 的迭代器吗？我们尝试自己来写一个迭代器：&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- 迭代器&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;list_iter&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;t&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; i&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; n&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;#&lt;/span&gt;t&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        i&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; i&lt;span class=&#34;token operator&#34;&gt;&amp;lt;=&lt;/span&gt;n &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; t&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; t&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;-- 创建表&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; iter &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;list_iter&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;t&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;-- 创建迭代器变量实例&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;true&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; element&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;iter&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;-- 使用迭代器&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; element&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;数据为:&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;element&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;strong&gt;Ps&lt;/strong&gt;：如果要创建一个闭包必须要创建其外部局部变量。所以一个典型的闭包的结构包含两个函数：一个是闭包自己；另一个是工厂（创建闭包的函数）。&lt;br&gt;
当然我们可以将这个迭代器应用于 for 循环中：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;for value in list_iter(t) do
    print(value)
end
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;迭代器小例子-访问文件&lt;/h4&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- 打开文件&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; file &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;hh.txt&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;r&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;-- 指定文件操作为读取&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;file &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;文件打开失败&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ReadFile&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; line&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;read&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;*l&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;-- 以行的形式进行读取&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;line &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; line&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; data &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ReadFile&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;data&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- 使用 while 的话&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; readfile&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;ReadFile&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;true&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; line&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;readfile&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; line&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;line&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3&gt;深入了解for循环&lt;/h3&gt;
&lt;p&gt;在上面的闭包迭代器中我们不难发现，如果使用 for 循环则可以免去 while 循环所需的迭代闭包变量，&lt;br&gt;
这样使用起来就比 while 循环要方便一些。那 for 循环是怎么做到的呢？&lt;br&gt;
让我们来看看 for 循环的格式：&lt;br&gt;
&lt;code&gt;for var_1, …, var_n in explist do block end&lt;/code&gt;&lt;br&gt;
在 for 循环我们可以使用多个参数，如之前我们使用的系统自带的表迭代器，我们可以获得 k 和 v 的值。&lt;br&gt;
在&lt;code&gt;in&lt;/code&gt;关键字后接需要被迭代的数据源列表（也就是说可以迭代多个列表），然后在&lt;code&gt;do&lt;/code&gt;后对遍历项进行处理。&lt;br&gt;
&lt;strong&gt;Ps&lt;/strong&gt;：其实在 lua 中，for 的执行顺序是这样的：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;首先，初始化，计算 in 后面表达式的值，表达式应该返回范性 for 需要的三个值：迭代函数，状态常量和控制变量；与多值赋值一样，如果表达式返回的结果个数不足三个会自动用 nil 补足，多出部分会被忽略。&lt;/li&gt;
&lt;li&gt;第二，将状态常量和控制变量作为参数调用迭代函数（注意：对于 for 结构来说，状态常量没有用处，仅仅在初始化时获取他的值并传递给迭代函数）。&lt;/li&gt;
&lt;li&gt;第三，将迭代函数返回的值赋给变量列表。&lt;/li&gt;
&lt;li&gt;第四，如果返回的第一个值为 nil 循环结束，否则执行循环体。&lt;/li&gt;
&lt;li&gt;第五，回到第二步再次调用迭代函数&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;font color=red&gt;从某种意义上来说，for 循环还是依赖于 while 循环做的优化&lt;/font&gt;。&lt;br&gt;
其等价为：&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; _f&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; _s&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; _var &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; explist&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;true&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; var_1&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; var_n &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;_f&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;_s&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; _var&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;_var &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; var_1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; _var &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;nil&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;block&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3&gt;无状态迭代器&lt;/h3&gt;
&lt;blockquote&gt;
  上面我们依据闭包的思想实现的迭代器其核心思想就是保留状态，那有没有一种方式&lt;font color=red&gt;无需保留状态&lt;/font&gt;构建迭代器呢？
&lt;/blockquote&gt;
&lt;p&gt;让我们回想一下，系统自带的&lt;code&gt;pairs(t)&lt;/code&gt;迭代器有使用到闭包吗？答案是：没有&lt;br&gt;
所以&lt;code&gt;pairs(t)&lt;/code&gt;迭代器就是一种无状态迭代器～&lt;br&gt;
 我们尝试着实现一个 pairs 的效果，其代码如下：&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;iter&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    i&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; v&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; v &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; i&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;v&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ipairs&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; iter&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; tt&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;45&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;46&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;100&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; key&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; value &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ipairs&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;tt&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;value&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;我们每次调用 ipairs 时，都自动去调用 iter，并且在调用时保留 iter 迭代函数，a 迭代数据，0 迭代索引。（很神奇吧，这种写法估计只有 lua 的作者才能想到，简直天才～）&lt;br&gt;
&lt;strong&gt;Ps&lt;/strong&gt;：同理，lua 中 ipairs 也是这样调用其他函数的（调用 next 函数）&lt;/p&gt;
&lt;h3&gt;多状态控制器&lt;/h3&gt;
&lt;p&gt;很多情况下，迭代器需要保存多个状态信息而不是简单的状态常量和控制变量，最&lt;br&gt;
简单的方法是使用闭包，还有一种方法就是将所有的状态信息封装到 table 内，将 table&lt;br&gt;
 作为迭代器的状态常量，因为这种情况下可以将所有的信息存放在 table 内，所以迭代函&lt;br&gt;
数通常不需要第二个参数。&lt;/p&gt;
&lt;p&gt;[toc]&lt;/p&gt;

 &lt;blockquote&gt;
  函数可以完成2件事，&lt;code&gt;完成工作&lt;/code&gt;或者&lt;code&gt;计算并返回结果&lt;/code&gt;。
&lt;/blockquote&gt;
&lt;h3&gt;函数语法&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function func_name (arguments-list)
statements-list
end
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Ps&lt;/strong&gt;：Lua 使用的函数可以是 Lua 编写也可以是其他语言编写，对于 Lua 程序员来说用什&lt;br&gt;
么语言实现的函数使用起来都一样。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function Show(a)
    print(a)
end
Show(100)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;返回多个值&lt;/h4&gt;
&lt;p&gt;在 lua 中函数可以返回多个值，例如 string.find，其返回匹配串 “开始和结束的下标”&lt;br&gt;
（如果不存在匹配串返回 nil）。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;s, e = string.find(&#34;hello Lua users&#34;, &#34;Lua&#34;)
print(s, e)  --&gt; 7 9
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;计算最大值和最大值的索引&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function MaxM(arr)
    local maxIndex=1
    local max=arr[maxIndex]
    for key, value in pairs(arr) do
        if value&gt;max then
            maxIndex=key
            max=value
        end
    end
    return max,maxIndex
end
local max,maxIndex=MaxM(&amp;#123;1.5,6,7,9&amp;#125;)
print(&#39;最大值和索引为:&#39;..max..&#39;  &#39;..maxIndex)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;返回函数&lt;/h4&gt;
&lt;p&gt;如&lt;code&gt;return fac()&lt;/code&gt;这样的形式就是返回函数，其意义是执行 fac 函数并返回 fac 的返回值，若没有返回 nil。&lt;/p&gt;
&lt;h4&gt;可变参数&lt;/h4&gt;
&lt;h5&gt;unpack&lt;/h5&gt;
&lt;p&gt;&lt;code&gt;unpack&lt;/code&gt;，接受一个数组作为输入参数，返回数组的所有元素。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;f = string.find
a = &amp;#123;&#34;hello&#34;, &#34;ll&#34;&amp;#125;
print(f(unpack(a))) --&gt; 3 4
&lt;/code&gt;&lt;/pre&gt;
&lt;h5&gt;...可变参数&lt;/h5&gt;
&lt;p&gt;可以使用… 表示不明确数量的可变参数，在使用时在函数中以表的形式获取。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function Sum(a,b,c,...)
    local arg=&amp;#123;...&amp;#125; --将可变参数存储到arg表中
    for key, value in pairs(arg) do
        print(value) -- 9 7 4 10
    end
end

Sum(5,4,8,9,7,4,10)
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;使用命名参数&lt;/h4&gt;
&lt;p&gt;由于 lua 使用弱类型的缘故，我们可以像这样使用命名参数，在这种情况下调用函数可以写为&lt;code&gt;函数名 &amp;#123;参数&amp;#125;&lt;/code&gt;的形式。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function Show(arg)
    print(arg.name..&#39;  &#39;..arg.title)
end

Show&amp;#123;name=&#39;小屋&#39;,title=&#39;学习lua&#39;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;深入理解函数&lt;/h3&gt;
&lt;p&gt;Lua 中的函数是带有词法定界（lexical scoping）的第一类值（first-class values）。&lt;br&gt;
&lt;font color=blue&gt;第一类值&lt;/font&gt;指：在 Lua 中函数和其他值（数值、字符串）一样，函数可以被存放在变量中，也可以存放在表中，可以作为函数的参数，还可以作为函数的返回值。&lt;/p&gt;
&lt;p&gt;&lt;font color=blue&gt;词法定界&lt;/font&gt;指：被嵌套的函数可以访问他外部函数中的变量。这一特性给 Lua 提供了强大的编程能力。&lt;/p&gt;
&lt;h4&gt;匿名函数&lt;/h4&gt;
&lt;p&gt;得益于上面的第一条规则，其实我们声明函数，本是 &lt;code&gt;fac=function(arg) body end&lt;/code&gt;。&lt;br&gt;
这个语句创建了一个匿名函数，并把这个函数赋值为 fac，我们就可以称这个函数为 fac 了。&lt;br&gt;
在&lt;strong&gt;&lt;code&gt;table.sort()&lt;/code&gt;&lt;/strong&gt;函数中使用匿名函数：&lt;/p&gt;
&lt;p&gt;在函数中接收 2 个参数，第一个参数接收一个表，第二个参数接收一个&lt;strong&gt;比较函数&lt;/strong&gt;。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;arr=&amp;#123;
    &amp;#123;name=&#39;A&#39;,age=16&amp;#125;,
    &amp;#123;name=&#39;B&#39;,age=20&amp;#125;,
    &amp;#123;name=&#39;C&#39;,age=9&amp;#125;,
&amp;#125;
table.sort(arr,function (a,b)
    return a.age&gt;b.age
end)

for key, value in pairs(arr) do
    for k, v in pairs(value) do
        print(k,v)
    end
end
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;以其他函数作为参数的函数在 Lua 中被称作高级函数，高级函数在 Lua 中并没有特&lt;br&gt;
权，只是 Lua 把函数当作第一类函数处理的一个简单的结果。&lt;/p&gt;
&lt;h4&gt;闭包&lt;/h4&gt;
&lt;p&gt;当一个函数内容嵌套另一个函数时，被嵌套的匿名函数还可以访问第一函数中的参数，这就被称为闭包；事实上仅有很少的语言支持这样的特性。&lt;br&gt;
来看看下面这个例子：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;function NewCount()
    local i=0
    return function ()
        i=i+1
        return i
    end
end
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在匿名函数中，我们依然可以直接正确的访问 i。&lt;/p&gt;
&lt;hr /&gt;
&lt;p&gt;现在，假如我们这样调用这个函数结果是怎样呢？&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local c1=NewCount()
local c2=NewCount()
print(c1())
print(c1())
print(c2())
print(c1())
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;!{函数闭包}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pLmxvbGkubmV0LzIwMjAvMDIvMDIvcjJmdHBHUGpzVmxtcXlnLnBuZw==&#34;&gt;https://i.loli.net/2020/02/02/r2ftpGPjsVlmqyg.png&lt;/span&gt;)&lt;br&gt;
 可以发现，函数的结果并非我们的预期，在第一函数体中的 i 的值可以被保留下来，而且 c1 和 c2 的保存值并不相同，这就是闭包。&lt;br&gt;
&lt;strong&gt;Ps&lt;/strong&gt;：我们把这个 i 称为&lt;font color=gree&gt;外部的局部变量或者 &lt;strong&gt;upvalue&lt;/strong&gt;&lt;/font&gt;。&lt;br&gt;
简单的说闭包是一个函数加上它可以正确访问的 upvalues。如果我们再次调用 newCounter，将创建一个新的局部变量 i，因此我们得到了一个作用在新的变量 i 上的新闭包。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;分析&lt;/strong&gt;：c1 和 c2 是作用同一个局部变量上的不同实例上的两个闭包。&lt;/p&gt;
&lt;h4&gt;使用闭包重写函数&lt;/h4&gt;
&lt;p&gt;闭包在完全不同的上下文中也是很有用途的。因为函数被存储在普通的变量内我们&lt;br&gt;
可以很方便的重定义或者预定义函数。通常当你需要原始函数有一个新的实现时可以重&lt;br&gt;
定义函数。例如你可以重定义 sin 使其接受一个度数而不是弧度作为参数：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local oldSin=math.sin
math.sin=function (x)
    return oldSin(x*math.pi/180)
end
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;通过这个特性我们可以对原函数进行修改，在某些时刻可以构建运行危险代码的沙盘。&lt;/p&gt;
&lt;h4&gt;局部函数&lt;/h4&gt;
&lt;p&gt;Lua 中函数既可以作为全局变量也可以作为局部变量，函数作为 table 的域。&lt;br&gt;
&lt;strong&gt;使用表声明函数&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;Lib=&amp;#123;&amp;#125;
Lib.foo=function (x,y)
    return x+y
end
Lib.goo=function (x,y)
    return x-y
end

Lib=&amp;#123;
    foo=function (x,y)
        return x+y
    end,
    goo=function (x,y)
        return x-y
    end
&amp;#125;

Lib=&amp;#123;&amp;#125;
function Lib.foo(x,y)
    return x+y
end
function Lib.goo(x,y)
    return x-y
end

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Ps&lt;/strong&gt;：在使用递归函数时，要注意要先声明函数在调用。&lt;/p&gt;
&lt;h4&gt;尾调用&lt;/h4&gt;
&lt;p&gt;尾调用是一种类似在函数结尾的 goto 调用，当函数最后一个动作是调用另外一个函&lt;br&gt;
数时，我们称这种调用尾调用。&lt;br&gt;
&lt;strong&gt;Ps&lt;/strong&gt;:Lua 中尾调用不消耗栈空间，由于尾调用不需要使用栈空间，那么尾调用递归的层次可以无限制的&lt;/p&gt;

 &lt;h3&gt;构建表&lt;/h3&gt;
&lt;p&gt;构造器是创建和初始化表的表达式。表是 Lua 特有的功能强大的东西。最简单的构&lt;br&gt;
造函数是 {}，用来创建一个空表。可以直接初始化数组:&lt;br&gt;
&lt;strong&gt;&lt;font color=red&gt;表的序号从 1 开始，并非 0&lt;/font&gt;。&lt;/strong&gt;&lt;br&gt;
&lt;strong&gt;Ps&lt;/strong&gt;：假如空引用，lua 也不会报错，会输出 nil。&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; numbers&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;7&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;9&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;numbers数据:&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;tostring&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;numbers&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;-- 输出 1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4&gt;构建自定义对象&lt;/h4&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; arr&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;arr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;xiao&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;arr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;age&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;16&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;arr的数据：&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;  name:&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;   age: &#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;arr&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;age&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4&gt;表的组成&lt;/h4&gt;
&lt;p&gt;表，可以包含任何类型的元素，也可以嵌套&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;arr&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;x&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;tip&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;text&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;func&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;print&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4&gt;构造注意事项&lt;/h4&gt;
&lt;p&gt;如果真的需要索引从 0 开始：&lt;br&gt;
&lt;strong&gt;Ps&lt;/strong&gt;：极力&lt;font color=red&gt;不推荐&lt;/font&gt;这么做，这么做将不能使用很多标准库。&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;arr&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Sunday&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Monday&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Tuesday&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;在构造表时既可以使用&lt;code&gt;,&lt;/code&gt;分隔元素也可以使用&lt;code&gt;；&lt;/code&gt;分隔元素。&lt;/p&gt;
&lt;h3&gt;流程控制&lt;/h3&gt;
&lt;p&gt;我们来看看 lua 中的流程控制语法～&lt;/p&gt;
&lt;h4&gt;分支&lt;/h4&gt;
&lt;p&gt;在 lua 中，每一个代码块的结束都要以&lt;strong&gt;end&lt;/strong&gt;结尾（有点 c++ 的味道）&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;A&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;false&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;AAA&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;BBB&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; a&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; a&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;a&gt;8&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;elseif&lt;/span&gt; a&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;  &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;a&gt;5&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;elseif&lt;/span&gt; a&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;a&gt;3&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;不满足&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4&gt;循环&lt;/h4&gt;
&lt;p&gt;使用步长 for 循环（可省略步长，默认为 1）&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- for 循环&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- 1 起点 10 终点 2 步长&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;正向数据为:&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;负向数据为：&#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;strong&gt;Ps&lt;/strong&gt;：在循环中不要改变控制变量的值，如果需要跳出循环可以使用&lt;code&gt;break&lt;/code&gt;关键字。&lt;/p&gt;
&lt;p&gt;使用 for 循环遍历表：&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;arr&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Sunday&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Monday&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Tuesday&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; key&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; value &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;pairs&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;arr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;key&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;   &#39;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;..&lt;/span&gt;value&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;while 循环&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; a&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; a&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    a&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;a&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;blockquote&gt;
  本系列将从零开始学习Lua的基本语法，用于之后使用&lt;font color=gree&gt;xLua&lt;/font&gt;进行unity&lt;font color=red&gt;热更新&lt;/font&gt;~
&lt;/blockquote&gt;
&lt;h3&gt;使用Vscode开发Lua&lt;/h3&gt;
&lt;p&gt;至少要下载 Lua 和 LuaDebug 这 2 个扩展～&lt;br&gt;
&lt;img data-src=&#34;https://i.loli.net/2020/02/01/raxtmuBAnLNIqQO.png&#34; alt=&#34;&#34;&gt;&lt;br&gt;
 看到 LuaDebug 的作者 actboy168，我有点惊讶，actboy168 是大名鼎鼎的 ydwe 作者之一，在以前自己玩 we 的时候用的编辑器就是 actboy168 大佬的，后面听说支持 lua 来代替 jass 编写游戏逻辑（那时候已经弃坑～）；好的，闲话不多说，我们来编写我们的第一个脚本。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;创建一个空文件夹并用vscode打开&lt;/li&gt;
&lt;li&gt;创建一个test.lua文件&lt;/li&gt;
&lt;li&gt;编写一行代码 &lt;code&gt;print(&#34;Hi,Lua~&#34;)&lt;/code&gt;（也可以使用&lt;font color=red&gt;&#39;&#39; 单引号&lt;/font&gt;）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2020/02/01/w4ds3ZquOteQX8p.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3&gt;基本使用&lt;/h3&gt;
&lt;h4&gt;数据类型&lt;/h4&gt;
&lt;p&gt;在 lua 中和 python 类型可以直接声明并使用，无需使用类型名，lua 自动分析数据类型。&lt;br&gt;
lua 的数据类型为（8 个）：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;nil 空&lt;/li&gt;
&lt;li&gt;boolean 布尔型&lt;/li&gt;
&lt;li&gt;number 数字型&lt;/li&gt;
&lt;li&gt;function 函数型&lt;/li&gt;
&lt;li&gt;string 字符串型&lt;/li&gt;
&lt;li&gt;userdata 用户自定义类型&lt;/li&gt;
&lt;li&gt;thread 线程型&lt;/li&gt;
&lt;li&gt;table 表型&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;可以使用&lt;code&gt;type()&lt;/code&gt;来查看类型～&lt;br&gt;
Ps: 在 lua 中不强制使用；结尾&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;--lua类型
print(type(3.4))
print(type(&#34;JK&#34;))
print(type(print))
print(type(3&gt;5))
print(type(nil))
&lt;/code&gt;&lt;/pre&gt;
&lt;h5&gt;Function类型&lt;/h5&gt;
&lt;p&gt;Function 类型有什么用呢？使用 Function 类型可以实现将函数作为函数的参数传递（类似 c++ 中的句柄，C# 中的委托）；有了这一特性，大大加强了代码的灵活性～&lt;/p&gt;
&lt;h5&gt;Userdata类型&lt;/h5&gt;
&lt;p&gt;userdata 类型可以表述用户自己创建的数据结构，也可以表示调用 c 语言函数库创建的新类型。&lt;/p&gt;
&lt;h4&gt;变量类型&lt;/h4&gt;
&lt;p&gt;&lt;font color=blue&gt;全局变量&lt;/font&gt;：全局变量是在整个程序中都可以使用的，默认声明的就是全局变量。&lt;br&gt;
&lt;font color=blue&gt;局部变量&lt;/font&gt;: 局部变量在全局变量前添加&lt;code&gt;local&lt;/code&gt;关键字声明的。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local a=100 --局部变量
b=&#39;Fasty&#39; --全局变量
&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;运算符&lt;/h4&gt;
&lt;p&gt;其他的数学运算符和其他语言是一致的，在这里看一下逻辑运算符&lt;code&gt;and or not&lt;/code&gt;。&lt;br&gt;
在 lua 中认为 false 和 nil 为假，其他为真。（0 也为真，c 语言中认为 0 为假，非 0 为真）&lt;br&gt;
值得注意的是使用逻辑运算符并非返回逻辑值：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;line-numbers&#34;&gt;local aa = 4 and 5 -- 若a为false则返回a，否则返回b  返回5
aa=nil and 7  --返回nil

local bb= 7 or 8 --若a为true则返回a，否则返回b 返回7
aa=nil or 8 --返回8
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;font color=gree&gt;小技巧:&lt;/font&gt;使用 &lt;code&gt;aa= nil or 5&lt;/code&gt; 可以判断 aa 是否为 nil，若为则赋值为 5。&lt;/p&gt;
&lt;p&gt;not 则为取反，一直返回布尔值。&lt;/p&gt;
&lt;p&gt;Ps：连接字符串使用&lt;code&gt;…&lt;/code&gt;，如&lt;code&gt;A…B&lt;/code&gt;。&lt;/p&gt;

 &lt;h3&gt;NaughtyAttributes&lt;/h3&gt;
&lt;p&gt;使用 NaughtyAttributes 可以很方便的管理 unity 属性面板的脚本属性，可以实现许多 unity 原先特性不能实现的效果，详情可以看向下面的 github 地址：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2Ricml6b3YvTmF1Z2h0eUF0dHJpYnV0ZXM=&#34;&gt;Github 项目地址&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;想水一期文章，好的，水完了～&lt;/p&gt;

 &lt;blockquote&gt;
  试想一下，有没有一种方法可以将&lt;font color=red&gt;异步&lt;/font&gt;的程序改为&lt;font color=blue&gt;同步&lt;/font&gt;，而又持有异步的效果呢？
&lt;/blockquote&gt;
&lt;h3&gt;Poll&lt;/h3&gt;
&lt;p&gt;&lt;font color=4e72b8&gt;意义：使用同步的方式解决异步问题。&lt;/font&gt;&lt;br&gt;
我们分析一下之前的程序逻辑，会发现我们使用 beginxxx 来开启新线程处理新的 socket，但是我们的客户端并不是实时的于服务器进行交互的（只在进行交互时，整个线程才是有效的，平时都处于阻塞等待状态。）&lt;br&gt;
有这么一种方式：&lt;br&gt;
&lt;code&gt;if (socket 有可读数据) socket.Receive ()&lt;/code&gt;&lt;br&gt;
&lt;code&gt;if (socket 缓冲区可写) socket.Send ()&lt;/code&gt;&lt;br&gt;
&lt;code&gt;if (socket 错误) 处理错误&lt;/code&gt;&lt;br&gt;
只要在阻塞方法前，加上一层判断，有数据可读才读，有数据可写才写，这样不就解决了程序卡住的问题吗？&lt;br&gt;
Ms 提供了 Poll 方法：&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;bool&lt;/span&gt;&lt;/span&gt; Poll&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; microSeconds；&lt;span class=&#34;token comment&#34;&gt;// 回应时间（ms） -1 一直等待  0 非阻塞&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    SelectMode mode；&lt;span class=&#34;token comment&#34;&gt;//SelectRead 是否可读 SelectWrite 是否可写 SelectError 是否发生错误&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4&gt;使用Poll改进客户端和服务器&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;font size=5px color=red&gt;客户端&lt;/font&gt;
对于客户端只需要在update中加一个&lt;code&gt;if(socket.Poll(0,SelectMode.SelectRead)) 执行读取&lt;/code&gt;就可以了。&lt;/li&gt;
&lt;li&gt;&lt;font size=5px color=green&gt;服务器&lt;/font&gt;
对于服务器，需要在主循环中对所有已连接的客户端进行状态监测，在其客户端可读时（即有数据发送给服务器时）进行读取操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;Select&lt;/h3&gt;
&lt;p&gt;&lt;font color=4e72b8&gt;意义：解决 Poll 下 Cpu 占用过高的问题&lt;/font&gt;&lt;/p&gt;
在前面没有提到cpu占用的事情，这里说一下，使用poll时，我们会在update中持续监听，程序在同一线程中非阻塞式的处理请求，会导致cpu占用过高的问题。
&lt;h4&gt;Select的解决思路&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;同时检测多个socket的状态&lt;/li&gt;
&lt;li&gt;将需操作的socket放入一个集合中&lt;/li&gt;
&lt;li&gt;如果没有可读写的socket就阻塞挂起&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;select 原型&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Select&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;IList&lt;/span&gt; checkRead&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 返回可读 Socket List&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;IList&lt;/span&gt; checkWrite&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;// 可写&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;IList&lt;/span&gt; checkError&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;// 错误&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt; microSeconds    &lt;span class=&#34;token comment&#34;&gt;// 超时时间&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;font color=blue&gt;【2020 年 1 月 17 日 18:40:19 下午】&lt;/font&gt;&lt;br&gt;
&lt;strong&gt;继续更新&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;使用 Select 时，我们需要定义几个列表，如上面原型所示这些列表应当实现了&lt;font size=4px color=red&gt; IList &lt;/font&gt;接口。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;创建可读列表CheckRead&lt;/li&gt;
&lt;li&gt;将所有连接Socket放入CheckRead中&lt;/li&gt;
&lt;li&gt;使用Socket.Select()对checkRead中的可读socket进行筛选&lt;/li&gt;
&lt;li&gt;对筛选后的可读对象进行读取&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;通过以上步骤，我们就使用 Select 完成了筛选，非常简单吧！&lt;/p&gt;
&lt;p&gt;从下一章开始按书的进度，我们就使用学习到的 Socket 知识写一个多人大乱斗游戏试试吧 ✌️ ~&lt;/p&gt;

 &lt;p&gt;在之前的基础上其实我们只需要将客户端发送给服务器的数据在服务器分发给连接的所有客户端即可实现聊天室的功能。&lt;br&gt;
不过在这里我对服务器端的代码重新优化了一下。&lt;/p&gt;
&lt;h3&gt;客户端连接实例&lt;/h3&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// 客户端连接实例&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;/summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;ClientEntity&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;Socket&lt;/span&gt; Socket &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;byte&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt; ReadBuff &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;/// 有效数据长度&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;/summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;int&lt;/span&gt;&lt;/span&gt; DataLength &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3&gt;主要代码&lt;/h3&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;Socket&lt;/span&gt; Socket &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;List&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;ClientEntity&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; ClientEntities &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 所有连接的客户端实例&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;string&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt; args&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;WriteLine&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Hi，服务器~&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            ClientEntities &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;List&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;ClientEntity&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token preprocessor property&#34;&gt;#&lt;span class=&#34;token directive keyword&#34;&gt;region&lt;/span&gt; 绑定ip&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token class-name&#34;&gt;IPAddress&lt;/span&gt; ipAddress &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; IPAddress&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Parse&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;127.0.0.1&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token class-name&#34;&gt;IPEndPoint&lt;/span&gt; ipEndPoint &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;IPEndPoint&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;ipAddress&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2233&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Socket &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;Socket&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;AddressFamily&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;InterNetwork&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; SocketType&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Stream&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; ProtocolType&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Tcp&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Bind&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;ipEndPoint&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Listen&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;// 最多支持同时监听 10 个客户端&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;WriteLine&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[服务器]启动成功！&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token preprocessor property&#34;&gt;#&lt;span class=&#34;token directive keyword&#34;&gt;endregion&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token comment&#34;&gt;// 绑定 Accept&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;BeginAccept&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;AcceptCallBack&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Socket&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            Console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;ReadLine&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3&gt;AcceptCallBack&lt;/h3&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;AcceptCallBack&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;IAsyncResult&lt;/span&gt; ar&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                Console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;WriteLine&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[服务器]有新客户端连接&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt;&lt;/span&gt; severSocket &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; ar&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;AsyncState &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Socket&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt;&lt;/span&gt; clientSocket &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; severSocket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;EndAccept&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;ar&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;// 创建客户端连接&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt;&lt;/span&gt; clientEntity &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;ClientEntity&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; Socket &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; clientSocket&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; ReadBuff &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;byte&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1024&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;// 创建客户端实例&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                ClientEntities&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Add&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;clientEntity&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 开始 Receive&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                clientEntity&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;BeginReceive&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;clientEntity&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ReadBuff&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; clientEntity&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ReadBuff&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Length&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; SocketFlags&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;None&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; ReceiveCallBack&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; clientEntity&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 继续 Accept&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                Socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;BeginAccept&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;AcceptCallBack&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; Socket&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;catch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;SocketException&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                Console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;WriteLine&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;[服务器Accept-Error]&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ErrorCode &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;-&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Message&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3&gt;ReceiveCallBack&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-csharp line-numbers&#34;&gt;  private static void ReceiveCallBack(IAsyncResult ar)
        &amp;#123;
            try
            &amp;#123;
                var clientEntity = ar.AsyncState as ClientEntity;   //获取传过来的客户端Socket
                var count = clientEntity.Socket.EndReceive(ar);
                if (count == 0)
                &amp;#123;
                    //关闭客户端连接
                    clientEntity.Socket.Close();
                    ClientEntities.Remove(clientEntity);
                    Console.WriteLine(&#34;[服务器]一个客户端已断开连接&#34;);

                    return;
                &amp;#125;
                var reciveStr = Encoding.UTF8.GetString(clientEntity.ReadBuff, 0, count); //读取客户端数据

                Console.WriteLine(&#34;[服务器]收到来自客户端数据：&#34; + reciveStr);


                var sendBytes = Encoding.UTF8.GetBytes(&#34;[服务器] 已收到来自客户端的消息：&#34;);
                clientEntity.DataLength = count;
                //进行数据分发
                foreach (var item in ClientEntities)
                &amp;#123;
                    item.Socket.BeginSend(sendBytes, 0, count, SocketFlags.None, SendCallBack, clientEntity);
                &amp;#125;

                //继续获取数据
                clientEntity.Socket.BeginReceive(clientEntity.ReadBuff, 0, clientEntity.ReadBuff.Length, SocketFlags.None, ReceiveCallBack, clientEntity);
            &amp;#125;
            catch (SocketException e)
            &amp;#123;

                Console.WriteLine(&#34;[服务器Receive-Error]&#34; + e.ErrorCode + &#34;-&#34; + e.Message);
            &amp;#125;
        &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;SendCallBack&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-csharp line-numbers&#34;&gt; private static void SendCallBack(IAsyncResult ar)
        &amp;#123;
            var clientEntity = ar.AsyncState as ClientEntity;
            Console.WriteLine(&#34;[服务器]已向客户端发送数据:&#34; + Encoding.UTF8.GetString(clientEntity.ReadBuff, 0, clientEntity.DataLength));
        &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;运行截图：&lt;/h3&gt;
&lt;p&gt;!{运行截图}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pLmxvbGkubmV0LzIwMjAvMDEvMTYvMjQ4RnFOS0dtN2poZ3YxLnBuZw==&#34;&gt;https://i.loli.net/2020/01/16/248FqNKGm7jhgv1.png&lt;/span&gt;)&lt;/p&gt;
&lt;p&gt;[toc]&lt;/p&gt;

 &lt;p&gt;&lt;font color=green&gt;[begin] 在 [/begin]&lt;/font&gt;第一章的学习内容中我们已经完成了基本的 Socket 通信，但是在第一章中我们只能处理一个客户端的消息。&lt;br&gt;
在实际游戏中，我们服务器需要对多个客户端进行监听和处理。&lt;/p&gt;
&lt;h3&gt;Begin XXX&lt;/h3&gt;
&lt;p&gt;每一个同步 API 对应着两个异步 API，分别是在原名称前面加上 Begin 和 End（如 BeginConnect 和 EndConnect）。使用异步程序可以防止程序卡住  。&lt;/p&gt;
&lt;h4&gt;例如：BenginConnect&lt;/h4&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
  &lt;th&gt;参数&lt;/th&gt;
  &lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
  &lt;td&gt;host&lt;/td&gt;
  &lt;td&gt;远程主机ip地址&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td&gt;port&lt;/td&gt;
  &lt;td&gt;端口号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td&gt;requestCallback&lt;/td&gt;
  &lt;td&gt;异步回调函数，其函数必须包含一个实现 &lt;font color=red&gt;&lt;strong&gt;IAsynResult&lt;/strong&gt;&lt;/font&gt;的对象&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
  &lt;td&gt;state&lt;/td&gt;
  &lt;td&gt;一个自定义对象，&lt;strong&gt;此对象会被传递给回调函数&lt;/strong&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;EndConnect&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
  &lt;th&gt;参数&lt;/th&gt;
  &lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
  &lt;td&gt;asyncResult&lt;/td&gt;
  &lt;td&gt;接收一个异步结果对象&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;font color=red&gt;其他的都大致相同&lt;/font&gt;&lt;br&gt;
[toc]&lt;/p&gt;
&lt;h3&gt;客户端&lt;/h3&gt;
&lt;p&gt;客户端使用 begin 和 end，修改为：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-csharp line-numbers&#34;&gt;using System;
using System.Net.Sockets;
using System.Text;
using System.Threading;
using UnityEngine;
using UnityEngine.UI;
public class Echo : MonoBehaviour
&amp;#123;
    public Button linkBtn;
    public Button sendBtn;
    public InputField inputField;
    public Text infoText;
    //套接字
    private Socket _socket;
    //接收缓冲区
    private byte[] _readBuff=new byte[1024];
    private string _recvStr=string.Empty;



    private void Start()
    &amp;#123;
        linkBtn.onClick.AddListener(Connection);
        sendBtn.onClick.AddListener(SendMessage);
        //Timer线程计时器
        var timer = new Timer((state) =&gt; &amp;#123; print(&#34;时间到&#34;); &amp;#125;,null,5000,0);
    &amp;#125;

    private void Update()
    &amp;#123;
        infoText.text = &#34;接收到来自服务器的数据：&#34;+_recvStr;
    &amp;#125;

    /// &lt;summary&gt;
    /// 连接
    /// &lt;/summary&gt;
    void Connection()
    &amp;#123;
        _socket=new Socket(SocketType.Stream,ProtocolType.Tcp);
        //异步进行连接
        _socket.BeginConnect(&#34;127.0.0.1&#34;, 8888, ConnectCallback, _socket);
        Debug.Log(&#34;开始连接...&#34;);
        // _socket.Connect(&#34;127.0.0.1&#34;,8888);
    &amp;#125;
    /// &lt;summary&gt;
    /// 连接回调
    /// &lt;/summary&gt;
    /// &lt;param name=&#34;ar&#34;&gt;&lt;/param&gt;
    void ConnectCallback(IAsyncResult ar)
    &amp;#123;
        try
        &amp;#123;
            var socket = ar.AsyncState as Socket;
            socket?.EndConnect(ar);    //连接完毕
            Debug.Log(&#34;连接成功！&#34;);
            //开始监听服务器端回复
            socket?.BeginReceive(_readBuff, 0, _readBuff.Length, 0, ReceiveCallback, socket);
        &amp;#125;
        catch (SocketException e)
        &amp;#123;
            Debug.Log(&#34;Socket连接错误:&#34;+e);
            throw;
        &amp;#125;
    &amp;#125;


    /// &lt;summary&gt;
    /// 接收回调
    /// &lt;/summary&gt;
    /// &lt;param name=&#34;ar&#34;&gt;&lt;/param&gt;
    void ReceiveCallback(IAsyncResult ar)
    &amp;#123;
        //ps：作者在这里提到，假如在send缓冲区的数据量太多，并且删除服务端receive相关的内容，使这些数据不能得到及时的释放，这时候客户端就会卡住。
        //所以我们也需要对send进行异步处理，防止堵塞。
        try
        &amp;#123;
            var socket = ar.AsyncState as Socket;
            var count = socket.EndReceive(ar);
            //注意在unity中，UI对象只能在主线程中更新，由于异步回调是由其他线程更新的，所以我只在这儿对_recvStr进行记录
            //并在主线程update中对UI对象进行更新。
            _recvStr = Encoding.UTF8.GetString(_readBuff, 0, count);

            socket.BeginReceive(_readBuff, 0, _readBuff.Length, 0, ReceiveCallback, socket);
        &amp;#125;
        catch (SocketException e)
        &amp;#123;
            Debug.Log(&#34;Socket错误：&#34;+e);
        &amp;#125;
    &amp;#125;

    /// &lt;summary&gt;
    /// 发送消息
    /// &lt;/summary&gt;
    void SendMessage()
    &amp;#123;
        var sendStr = inputField.text;
        var sendBytes = System.Text.Encoding.UTF8.GetBytes(sendStr);
        // _socket.Send(sendBytes);
        /*
         * 值得注意的是，send方法的过程只是将数据写入到缓冲区，由操作系统进行重传和确认。
         * send成功只表示，数据成功吸入缓冲区，并不代表对方已经收到数据。
         */
        _socket.BeginSend(sendBytes, 0, sendBytes.Length, 0, SendCallback, _socket);

    &amp;#125;

    /// &lt;summary&gt;
    /// Send回调
    /// &lt;/summary&gt;
    /// &lt;param name=&#34;ar&#34;&gt;&lt;/param&gt;
    void SendCallback(IAsyncResult ar)
    &amp;#123;
        try
        &amp;#123;
            var socket = ar.AsyncState as Socket;
            var count = socket?.EndSend(ar);
            /*
             * 在这里作者提到，一般来说收发的数据长度应当保持一致，但是当我们的数据大小超过缓冲区的大小时，我们需要再次调用相关的send或reivce方法
             * 发送或接收剩余的数据。（在后面的章节再介绍）
             */
            Debug.Log(&#34;socket 发送成功 发送字节数：&#34;+count);
        &amp;#125;
        catch (SocketException e)
        &amp;#123;
           Debug.Log(&#34;Socket Send 错误：&#34;+e);
        &amp;#125;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;服务器&lt;/h3&gt;
&lt;p&gt;在上一章中，我们的服务器使用单线程的阻塞，也就是说每次只能处理一个客户端的请求，现在我们也将服务器改为多线程模式，让他可以同时处理多个线程。（多个客户端请求）&lt;br&gt;
其代码实现如下：&lt;/p&gt;
&lt;h4&gt;创建一个clientState类存储客户端状态&lt;/h4&gt;
&lt;pre&gt;&lt;code class=&#34;language-csharp line-numbers&#34;&gt;using System.Net.Sockets;

namespace netWork_Server
&amp;#123;
    /// &lt;summary&gt;
    /// 连接状态
    /// &lt;/summary&gt;
    public class ClientState
    &amp;#123;
        public Socket Socket &amp;#123; get; set; &amp;#125;
        public byte[] ReadBuff &amp;#123; get; set; &amp;#125;

        public ClientState()
        &amp;#123;
            ReadBuff=new byte[1024];
        &amp;#125;
    &amp;#125;
&amp;#125;

&lt;/code&gt;&lt;/pre&gt;
&lt;h4&gt;主代码&lt;/h4&gt;
&lt;pre&gt;&lt;code class=&#34;language-csharp line-numbers&#34;&gt;using System;
using System.Collections.Generic;
using System.Net;
using System.Net.Sockets;
using System.Text;

namespace netWork_Server
&amp;#123;


    internal class Program
    &amp;#123;
        private static Socket socket;
        static  Dictionary&lt;Socket,ClientState&gt; _clientStates=new Dictionary&lt;Socket, ClientState&gt;();

        public static void Main(string[] args)
        &amp;#123;


            Console.WriteLine(&#34;Hi&#34;);

            socket=new Socket(AddressFamily.InterNetwork,SocketType.Stream,ProtocolType.Tcp);
            IPAddress ipAddress = IPAddress.Parse(&#34;127.0.0.1&#34;);
            IPEndPoint ipEndPoint=new IPEndPoint(ipAddress,8888);
            socket.Bind(ipEndPoint);
            //listen
            socket.Listen(0);
            Console.WriteLine(&#34;[服务器] 启动成功&#34;);
            //Accept
            //当客户端连接上服务器时，调用AcceptCallback
            socket.BeginAccept(AcceptCallback,socket);
            Console.ReadLine();
        &amp;#125;

        /// &lt;summary&gt;
        /// Accept回调
        /// &lt;/summary&gt;
        /// &lt;param name=&#34;ar&#34;&gt;&lt;/param&gt;
        private static void AcceptCallback(IAsyncResult ar)
        &amp;#123;
            try
            &amp;#123;
                Console.WriteLine(&#34;[服务器] 连接到新客户端&#34;);
                Socket listenfd=ar.AsyncState as Socket;
                Socket clientfd = listenfd.EndAccept(ar);
                ClientState state=new ClientState();
                state.Socket = clientfd;
                _clientStates.Add(clientfd,state);
                //进行Receive
                clientfd.BeginReceive(state.ReadBuff, 0, 1024, 0,ReceiveCallback, state);
                //继续Accept
                listenfd.BeginAccept(AcceptCallback, listenfd);
            &amp;#125;
            catch (SocketException e)
            &amp;#123;
                Console.WriteLine(&#34;Socket Accept错误：&#34;+e);
                throw;
            &amp;#125;

        &amp;#125;

        /// &lt;summary&gt;
        /// Receive回调
        /// &lt;/summary&gt;
        /// &lt;param name=&#34;ar&#34;&gt;&lt;/param&gt;
        static void ReceiveCallback(IAsyncResult ar)
        &amp;#123;
            try
            &amp;#123;
                var state = ar.AsyncState as ClientState;
                var clientfd = state.Socket;
                int count = clientfd.EndReceive(ar);
                //关闭客户端
                if (count==0)
                &amp;#123;
                    clientfd.Close();
                    _clientStates.Remove(clientfd);
                    Console.WriteLine(&#34;Socket Close!&#34;);
                    return;
                &amp;#125;

                string recvStr = Encoding.UTF8.GetString(state.ReadBuff,0,count);
                Console.WriteLine(&#34;[客户端]&#34;+recvStr);
                byte[] sendBytes = Encoding.UTF8.GetBytes(&#34;echo&#34; + recvStr);

                clientfd.Send(sendBytes);
                //继续获取数据
                clientfd.BeginReceive(state.ReadBuff, 0, 1024, 0, ReceiveCallback, state);

            &amp;#125;
            catch (SocketException e)
            &amp;#123;
                Console.WriteLine(&#34;Socket Receive 错误：&#34;+e);
            &amp;#125;
        &amp;#125;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;进行会话&lt;/h3&gt;
&lt;p&gt;我们将客户端生成一份，让生成的客户端和编辑器客户端同时与服务器连接并进行会话操作。&lt;br&gt;
其效果如图所示：&lt;br&gt;
!{服务器端}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pLmxvbGkubmV0LzIwMjAvMDEvMTQva1ZyUUlXcGVqWEJSbWFuLnBuZw==&#34;&gt;https://i.loli.net/2020/01/14/kVrQIWpejXBRman.png&lt;/span&gt;)&lt;br&gt;
!{客户端}(&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pLmxvbGkubmV0LzIwMjAvMDEvMTQvSmRiYVJMcHQ1azFob2dzLnBuZw==&#34;&gt;https://i.loli.net/2020/01/14/JdbaRLpt5k1hogs.png&lt;/span&gt;)&lt;/p&gt;
&lt;h3&gt;结语&lt;/h3&gt;
&lt;p&gt;这是这一章的前半部分，完成了在 socket 下的多线程模式，其中在字符编码部分，原书使用了 Default，这导致可能没法解析中文字符，所以我将其改为了固定的 UTF8 做解析。&lt;br&gt;
感谢您读完这篇文章，在本章的下半部分将实现一个聊天室。&lt;/p&gt;

 &lt;h3&gt;序&lt;/h3&gt;
&lt;p&gt;这本书买了蛮久的，趁着寒假的时间拿出来学习一下，争取这个假期把这本书看完，把里面的实例代码都自己敲一遍，加深理解。&lt;br&gt;
这是一个长期更新的系列：全书共&lt;font color=red&gt;十二章&lt;/font&gt;就算是每个章节写一篇文章也至少要写十二篇文章，希望自己可以坚持着书看完，把博客写完。&lt;/p&gt;
&lt;h3&gt;Socket连接步骤&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;示例图&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;type=&amp;quot;text/javascript&amp;quot;&amp;gt;document.write(&amp;quot;graph TD;
    Client--&amp;gt;|连接服务器|Connect;
    Connect--&amp;gt;|发送消息|Send;
    Connect--&amp;gt;|三次握手|Accept;
    Send--&amp;gt;|接收服务器消息|Receive;
    Send--&amp;gt;|向服务器发送数据|ServerReceive;
    Receive--&amp;gt;|断开连接|Close;
    Close--&amp;gt;|四次挥手|ServerClose;
    Server--&amp;gt;|绑定Ip和端口|Bind;
    Bind--&amp;gt;|开启监听|Listen;
    Listen--&amp;gt;|接收客户端连接请求|Accept;
    Accept--&amp;gt;|接收客户端数据|ServerReceive;
    ServerReceive--&amp;gt;|给客户端发送数据|ServerSend;
    ServerSend--&amp;gt;|发送数据给客户端|Receive;
    ServerSend--&amp;gt;|断开连接|ServerClose;
&amp;quot;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h3&gt;Echo&lt;/h3&gt;
&lt;p&gt;第一章主要讲解了网络的连接方式，在例子中初步实现了一个使用 Socket 的 TCP 通信的客户端和服务端案例。&lt;br&gt;
客户端代码如下：&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;figcaption data-lang=&#34;C#&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;using&lt;/span&gt; &lt;span class=&#34;token namespace&#34;&gt;System&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Net&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Sockets&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;using&lt;/span&gt; &lt;span class=&#34;token namespace&#34;&gt;UnityEngine&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;using&lt;/span&gt; &lt;span class=&#34;token namespace&#34;&gt;UnityEngine&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;UI&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Echo&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token type-list&#34;&gt;&lt;span class=&#34;token class-name&#34;&gt;MonoBehaviour&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Button&lt;/span&gt; linkBtn&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Button&lt;/span&gt; sendBtn&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;InputField&lt;/span&gt; inputField&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Text&lt;/span&gt; infoText&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Socket&lt;/span&gt; _socket&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Start&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        linkBtn&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;onClick&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;AddListener&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Connection&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        sendBtn&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;onClick&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;AddListener&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SendMessage&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// 连接&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;/summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Connection&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        _socket&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;Socket&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;SocketType&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Stream&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;ProtocolType&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Tcp&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        _socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Connect&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;127.0.0.1&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8888&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// 发送消息&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;/// &amp;lt;/summary&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token return-type class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;SendMessage&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt;&lt;/span&gt; sendStr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; inputField&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;text&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt;&lt;/span&gt; sendBytes &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; System&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Text&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Encoding&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Default&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;GetBytes&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;sendStr&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        _socket&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;Send&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;sendBytes&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 接收&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt;&lt;/span&gt; readBuff &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token constructor-invocation class-name&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;byte&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1024&lt;/span&gt;&lt;span class=&#34;token 